const SignatureBox  = ({ data,  onConfirm,  }) => {
	
	const sigPad = useRef(null);

	const clear = () =>{
		updStore("b64_signature",null);
		sigPad.current.clear()
	}

	const save = () =>{
		let b64 = sigPad.current.getTrimmedCanvas().toDataURL('image/png');
		onConfirm && onConfirm(b64)
		close();
	}

	const close  = ()  => {
		data?.modalID && CloseModal({id:data?.modalID})
	}


	return(
		<div style={{
			maxHeight: "80vh",
			width: "820px",
			overflow: "auto",
			background: "var(--dark-800)",
			borderRadius: 13,
			padding: "10px 19px"
		}}>
			<div className="_dsplFlx ">
				<p className="form_title">
					Signature
				</p>
				<div className="flexSpace"/>
				
			</div>
			
			
			
			
			<div style={{
				padding: 5,
				borderRadius: 13,
				border:"1px solid #999",
				margin: "5px 2px "
			}}>
				<SignatureCanvas penColor='#090909'
					canvasProps={{width: 650, height: 200, className: 'sigCanvas'}}
					ref={sigPad} />
			</div>
		


			
				<div className="_dsplFlx ">
					<div className="card">
						<GrayButton label={"Clear"} clickHandler={clear}/>
						
					</div>
					<div className="flexSpace"/>
					<div className="card">
						<GrayButton label={"Confirm"} clickHandler={save}/>
						
					</div>
				</div>
			


		</div>
	)

}



export default SignatureBox;








